import{_ as a,o as t,c as d,ap as r}from"./chunks/framework.BaP7s1d0.js";const u=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/FAQ.md","filePath":"zh/guide/FAQ.md"}'),i={name:"zh/guide/FAQ.md"};function h(c,e,o,l,n,s){return t(),d("div",null,[...e[0]||(e[0]=[r('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to “常见问题”">​</a></h1><h2 id="支持-vue-3-吗" tabindex="-1">支持 Vue 3 吗？ <a class="header-anchor" href="#支持-vue-3-吗" aria-label="Permalink to “支持 Vue 3 吗？”">​</a></h2><p>支持。当前 UI 集成层基于 Vue 3。</p><h2 id="支持-vue-2-吗" tabindex="-1">支持 Vue 2 吗？ <a class="header-anchor" href="#支持-vue-2-吗" aria-label="Permalink to “支持 Vue 2 吗？”">​</a></h2><p>不支持。</p><h2 id="支持-react-吗" tabindex="-1">支持 React 吗？ <a class="header-anchor" href="#支持-react-吗" aria-label="Permalink to “支持 React 吗？”">​</a></h2><p>当前仓库没有 React 集成层，文档和内置组件均以 Vue 3 为准。</p><h2 id="能搭配其他组件库吗" tabindex="-1">能搭配其他组件库吗？ <a class="header-anchor" href="#能搭配其他组件库吗" aria-label="Permalink to “能搭配其他组件库吗？”">​</a></h2><p>可以。模块组件、参数面板组件和宿主应用 UI 都可以使用你自己的组件库，例如 Element Plus、Ant Design Vue 或 Naive UI。</p><h2 id="仓库里主要有哪些包" tabindex="-1">仓库里主要有哪些包？ <a class="header-anchor" href="#仓库里主要有哪些包" aria-label="Permalink to “仓库里主要有哪些包？”">​</a></h2><table tabindex="0"><thead><tr><th>包名</th><th>说明</th></tr></thead><tbody><tr><td><code>@ptahjs/kernel</code></td><td>核心数据层，提供类型常量、资源系统和底层能力</td></tr><tr><td><code>@ptahjs/runtime</code></td><td>运行时层，负责 Schema 编译、查询和生命周期处理</td></tr><tr><td><code>@ptahjs/designer</code></td><td>设计器层，提供历史记录、拖拽和编辑操作</td></tr><tr><td><code>@ptahjs/ui-vue</code></td><td>Vue 3 集成层，提供组件、渲染器和启动入口</td></tr><tr><td><code>@ptahjs/shared</code></td><td>公共工具函数</td></tr><tr><td><code>@ptahjs/dnd</code></td><td>拖拽引擎</td></tr></tbody></table><h2 id="预览模式和设计器模式有什么区别" tabindex="-1">预览模式和设计器模式有什么区别？ <a class="header-anchor" href="#预览模式和设计器模式有什么区别" aria-label="Permalink to “预览模式和设计器模式有什么区别？”">​</a></h2><ul><li>预览模式使用 <code>useRuntimeApp()</code>，只负责渲染页面。</li><li>设计器模式使用 <code>useDesignerApp()</code>，额外提供 <code>runtime.designer</code>、历史记录和拖拽能力。</li></ul><h2 id="现在应该优先用哪个启动-api" tabindex="-1">现在应该优先用哪个启动 API？ <a class="header-anchor" href="#现在应该优先用哪个启动-api" aria-label="Permalink to “现在应该优先用哪个启动 API？”">​</a></h2><p>优先使用 <code>createPtah()</code>。旧文档里曾出现过其他创建方式，但当前公开入口以 <code>createPtah()</code> 为准。</p>',15)])])}const m=a(i,[["render",h]]);export{u as __pageData,m as default};
